      t0 = t0 * t0 + f0;
      t1 = t1 * t1 + f1;
      t2 = t2 * t2 + f2;
      t3 = t3 * t3 + f3;
      t4 = t4 * t4 + f4;
      t5 = t5 * t5 + f5;
      t6 = t6 * t6 + f6;
      t7 = t7 * t7 + f7;
    }

    if constexpr (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
    if constexpr (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
    if constexpr (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
    if constexpr (compute_iterations % 8 > 3) t3 = t3 * t3 + f3;
    if constexpr (compute_iterations % 8 > 4) t4 = t4 * t4 + f4;
    if constexpr (compute_iterations % 8 > 5) t5 = t5 * t5 + f5;
    if constexpr (compute_iterations % 8 > 6) t6 = t6 * t6 + f6;

    local_sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
