using benchmark_clock = std::chrono::steady_clock;

static int base_cuda_multiprocessors = 1;

template <typename T>
__device__ inline void atomicAddTyped(T* addr, T val);

template <>
__device__ inline void atomicAddTyped<int>(int* addr, int val) {
  atomicAdd(addr, val);
}

template <>
__device__ inline void atomicAddTyped<float>(float* addr, float val) {
  atomicAdd(addr, val);
}

#if __CUDA_ARCH__ < 600
__device__ inline double atomicAddDoubleCompat(double* address, double val) {
  unsigned long long int* address_as_ull =
      reinterpret_cast<unsigned long long int*>(address);
  unsigned long long int old = *address_as_ull, assumed;
  do {
    assumed = old;
    old = atomicCAS(address_as_ull, assumed,
                    __double_as_longlong(val + __longlong_as_double(assumed)));
  } while (assumed != old);
  return __longlong_as_double(old);
}
#endif

template <>
__device__ inline void atomicAddTyped<double>(double* addr, double val) {
#if __CUDA_ARCH__ < 600
  atomicAddDoubleCompat(addr, val);
#else
  atomicAdd(addr, val);
#endif
}

template <typename Element, unsigned int compute_iterations, size_t static_chunk_size>
__global__ void bench_kernel(Element* data, size_t len, Element* global_sum) {
  const size_t num_chunks = (len + static_chunk_size - 1) / static_chunk_size;
  Element thread_sum = static_cast<Element>(0);

  for (size_t chunk = blockIdx.x; chunk < num_chunks; chunk += gridDim.x) {
    const size_t base = chunk * static_chunk_size;

#ifdef BASELINE_IMPL
    Element f = data[base + 0];

    for (size_t i = threadIdx.x; i < static_chunk_size; i += blockDim.x) {
      Element t = data[base + i];
      for (unsigned int j = 0; j < compute_iterations; j++) {
        t = t * t + f;
      }
      thread_sum += t;
    }
#else
    Element f0 = data[base + 0];
    Element f1 = data[base + 1];
    Element f2 = data[base + 2];
    Element f3 = data[base + 3];
    Element f4 = data[base + 4];
    Element f5 = data[base + 5];
    Element f6 = data[base + 6];
    Element f7 = data[base + 7];

    for (size_t i = threadIdx.x; i < static_chunk_size; i += blockDim.x) {
      Element d = data[base + i];
      Element t0 = d, t1 = d, t2 = d, t3 = d, t4 = d, t5 = d, t6 = d, t7 = d;

      for (unsigned int j = 0; j < (compute_iterations / 8); j++) {
        t0 = t0 * t0 + f0;
        t1 = t1 * t1 + f1;
        t2 = t2 * t2 + f2;
        t3 = t3 * t3 + f3;
        t4 = t4 * t4 + f4;
        t5 = t5 * t5 + f5;
        t6 = t6 * t6 + f6;
        t7 = t7 * t7 + f7;
      }

      if (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
      if (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
      if (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
      if (compute_iterations % 8 > 3) t3 = t3 * t3 + f3;
      if (compute_iterations % 8 > 4) t4 = t4 * t4 + f4;
      if (compute_iterations % 8 > 5) t5 = t5 * t5 + f5;
      if (compute_iterations % 8 > 6) t6 = t6 * t6 + f6;

      thread_sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
    }
#endif
  }

  extern __shared__ unsigned char smem[];
  Element* sdata = reinterpret_cast<Element*>(smem);
  sdata[threadIdx.x] = thread_sum;
  __syncthreads();

  for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
    if (threadIdx.x < s) {
      sdata[threadIdx.x] += sdata[threadIdx.x + s];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    atomicAddTyped(global_sum, sdata[0]);
  }
}

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len, const Element seed1, const Element seed2, Element* src,
             int launch_blocks = -1) {
  (void)seed1;
  (void)seed2;

  constexpr size_t static_chunk_size = 4096;
  const size_t num_chunks = (len + static_chunk_size - 1) / static_chunk_size;

  int blocks = launch_blocks > 0 ? launch_blocks
                                 : static_cast<int>(std::min<size_t>(num_chunks, 65535));
  if (blocks < 1) blocks = 1;

  constexpr int threads = 256;
  Element* d_sum = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&d_sum, sizeof(Element)));
  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(Element)));

  bench_kernel<Element, compute_iterations, static_chunk_size>
      <<<blocks, threads, threads * sizeof(Element)>>>(src, len, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  CUDA_SAFE_CALL(cudaMemcpy(src, d_sum, sizeof(Element), cudaMemcpyDeviceToDevice));
  CUDA_SAFE_CALL(cudaFree(d_sum));

  return len;
}

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = static_cast<int>(size / sizeof(double));
  auto timer_start = benchmark_clock::now();

  double* ptr = reinterpret_cast<double*>(c);
  bench<double, 16>(num_elements, 1., -1., ptr);

  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() /
         1000.;
}

template <typename OpFull, typename OpHalf>
auto benchmark_cuda(OpFull op_full, OpHalf op_half) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op_full();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op_full();
    measurements.push_back(duration);
  }

  if (base_cuda_multiprocessors > 1) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      duration = op_half();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, static_cast<int>(compute_iterations)};

  constexpr size_t static_chunk_size = 4096;

  float* c_as_float = reinterpret_cast<float*>(c);
  const size_t chunks_sp = (cs.element_count<float>() + static_chunk_size - 1) / static_chunk_size;
  const int blocks_sp_full = static_cast<int>(std::min<size_t>(chunks_sp, 65535));
  const int blocks_sp_half = std::max(1, blocks_sp_full / 2);

  auto kernel_time_mad_sp = benchmark_cuda(
      [&] {
        return measure_operation([&] {
          bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f,
                                           c_as_float, blocks_sp_full);
        });
      },
      [&] {
        return measure_operation([&] {
          bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f,
                                           c_as_float, blocks_sp_half);
        });
      });

  double* c_as_double = reinterpret_cast<double*>(c);
  const size_t chunks_dp = (cs.element_count<double>() + static_chunk_size - 1) / static_chunk_size;
  const int blocks_dp_full = static_cast<int>(std::min<size_t>(chunks_dp, 65535));
  const int blocks_dp_half = std::max(1, blocks_dp_full / 2);

  auto kernel_time_mad_dp = benchmark_cuda(
      [&] {
