using benchmark_clock = std::chrono::steady_clock;

template <typename T, unsigned int compute_iterations, unsigned int static_chunk_size>
__global__ void bench_kernel(const T* src, T* global_sum, size_t num_chunks) {
  const size_t chunk_id = static_cast<size_t>(blockIdx.x);
  if (chunk_id >= num_chunks) return;

  const size_t base = chunk_id * static_chunk_size;

  const T f0 = src[base + 0];
  const T f1 = src[base + 1];
  const T f2 = src[base + 2];
  const T f3 = src[base + 3];
  const T f4 = src[base + 4];
  const T f5 = src[base + 5];
  const T f6 = src[base + 6];
  const T f7 = src[base + 7];

  T local_sum = 0;
  for (size_t i = static_cast<size_t>(threadIdx.x); i < static_chunk_size; i += blockDim.x) {
    T d = src[base + i];

    T t0 = d, t1 = d, t2 = d, t3 = d;
    T t4 = d, t5 = d, t6 = d, t7 = d;

#pragma unroll
    for (size_t j = 0; j < compute_iterations / 8; ++j) {
      t0 = t0 * t0 + f0;
      t1 = t1 * t1 + f1;
      t2 = t2 * t2 + f2;
      t3 = t3 * t3 + f3;
      t4 = t4 * t4 + f4;
      t5 = t5 * t5 + f5;
      t6 = t6 * t6 + f6;
      t7 = t7 * t7 + f7;
    }

    if constexpr (0 < compute_iterations % 8) t0 = t0 * t0 + f0;
    if constexpr (1 < compute_iterations % 8) t1 = t1 * t1 + f1;
    if constexpr (2 < compute_iterations % 8) t2 = t2 * t2 + f2;
    if constexpr (3 < compute_iterations % 8) t3 = t3 * t3 + f3;
    if constexpr (4 < compute_iterations % 8) t4 = t4 * t4 + f4;
    if constexpr (5 < compute_iterations % 8) t5 = t5 * t5 + f5;
    if constexpr (6 < compute_iterations % 8) t6 = t6 * t6 + f6;

    local_sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
  }

  extern __shared__ unsigned char smem_raw[];
  T* smem = reinterpret_cast<T*>(smem_raw);
  smem[threadIdx.x] = local_sum;
  __syncthreads();

  for (unsigned int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
    if (threadIdx.x < stride) {
      smem[threadIdx.x] += smem[threadIdx.x + stride];
    }
    __syncthreads();
  }

  if (threadIdx.x == 0) {
    atomicAdd(global_sum, smem[0]);
  }
}

template <typename T>
__global__ void write_back_first(T* dst, const T* value) {
  if (blockIdx.x == 0 && threadIdx.x == 0) {
    dst[0] = value[0];
  }
}

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len, const Element /*seed1*/, const Element /*seed2*/, Element* d_src,
             Element* d_sum) {
  constexpr size_t static_chunk_size = 4096;
  const size_t num_chunks = (len + static_chunk_size - 1) / static_chunk_size;

  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(Element)));

  constexpr int threads = 256;
  bench_kernel<Element, compute_iterations, static_chunk_size>
      <<<static_cast<unsigned int>(num_chunks), threads, threads * sizeof(Element)>>>(d_src, d_sum,
                                                                                       num_chunks);
  CUDA_SAFE_CALL(cudaGetLastError());

  write_back_first<Element><<<1, 1>>>(d_src, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());

  return len;
}

template <typename Op>
double measure_operation(Op op) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));

  CUDA_SAFE_CALL(cudaEventRecord(start));
  op();
  CUDA_SAFE_CALL(cudaEventRecord(stop));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));

  float ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, start, stop));

  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));
  return static_cast<double>(ms);
}

template <typename Op>
double benchmark_gpu(Op op, bool do_half_thread_phase) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op();
  std::vector<decltype(duration)> measurements;
  measurements.reserve((total_runs - 1) + (do_half_thread_phase ? (total_half_thread_runs - 1) : 0));

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  if (do_half_thread_phase) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      duration = op();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(measurements.begin(), measurements.end());
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t ms, int ci) : memory_space_{ms}, compute_iterations_{ci} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
double runbench_warmup(void* d_buf, size_t size_bytes, double* d_sum_double) {
  const int item_1 = static_cast<int>(size_bytes / sizeof(double));
  auto* ptr = reinterpret_cast<double*>(d_buf);
  return measure_operation([&] { bench<double, compute_iterations>(item_1, 1.0, -1.0, ptr, d_sum_double); });
}

