#include <stdio.h>
#include <string.h>
#include <math.h>
#include <stdlib.h>
#include <chrono>

struct Node
{
    int starting;
    int no_of_edges;
};

static FILE *fp;

static void Usage(int argc, char **argv)
{
    (void)argc;
    fprintf(stderr, "Usage: %s <num_threads> <input_file>\n", argv[0]);
}

__global__ void bfs_kernel_expand(
    int no_of_nodes,
    const Node *graph_nodes,
    const int *graph_edges,
    bool *graph_mask,
    bool *updating_graph_mask,
    const bool *graph_visited,
    int *cost)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < no_of_nodes && graph_mask[tid] == true)
    {
        graph_mask[tid] = false;
        int start = graph_nodes[tid].starting;
        int end = start + graph_nodes[tid].no_of_edges;
        for (int i = start; i < end; i++)
        {
            int id = graph_edges[i];
            if (!graph_visited[id])
            {
                cost[id] = cost[tid] + 1;
                updating_graph_mask[id] = true;
            }
        }
    }
}

__global__ void bfs_kernel_update(
    int no_of_nodes,
    bool *graph_mask,
    bool *updating_graph_mask,
    bool *graph_visited,
    int *stop)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < no_of_nodes && updating_graph_mask[tid] == true)
    {
        graph_mask[tid] = true;
        graph_visited[tid] = true;
        updating_graph_mask[tid] = false;
        *stop = 1;
    }
}

static void BFSGraph(int argc, char **argv)
{
    int no_of_nodes = 0;
    int edge_list_size = 0;
    char *input_f;
    int num_omp_threads;

    if (argc != 3)
    {
        Usage(argc, argv);
        exit(0);
    }

    num_omp_threads = atoi(argv[1]);
    (void)num_omp_threads;
    input_f = argv[2];

    printf("Reading File\n");

    fp = fopen(input_f, "r");
    if (!fp)
    {
        printf("Error Reading graph file\n");
        return;
    }

    int source = 0;
    fscanf(fp, "%d", &no_of_nodes);

    Node *h_graph_nodes = (Node *)malloc(sizeof(Node) * no_of_nodes);
    bool *h_graph_mask = (bool *)malloc(sizeof(bool) * no_of_nodes);
    bool *h_updating_graph_mask = (bool *)malloc(sizeof(bool) * no_of_nodes);
    bool *h_graph_visited = (bool *)malloc(sizeof(bool) * no_of_nodes);

    int start, edgeno;
    for (unsigned int i = 0; i < (unsigned int)no_of_nodes; i++)
    {
        fscanf(fp, "%d %d", &start, &edgeno);
        h_graph_nodes[i].starting = start;
        h_graph_nodes[i].no_of_edges = edgeno;
        h_graph_mask[i] = false;
        h_updating_graph_mask[i] = false;
        h_graph_visited[i] = false;
    }

    fscanf(fp, "%d", &source);

    h_graph_mask[source] = true;
    h_graph_visited[source] = true;

    fscanf(fp, "%d", &edge_list_size);

    int id, cost;
    int *h_graph_edges = (int *)malloc(sizeof(int) * edge_list_size);
    for (int i = 0; i < edge_list_size; i++)
    {
        fscanf(fp, "%d", &id);
        fscanf(fp, "%d", &cost);
        h_graph_edges[i] = id;
    }

    if (fp)
        fclose(fp);

    int *h_cost = (int *)malloc(sizeof(int) * no_of_nodes);
    for (int i = 0; i < no_of_nodes; i++)
        h_cost[i] = -1;
    h_cost[source] = 0;

    Node *d_graph_nodes = nullptr;
    int *d_graph_edges = nullptr;
    bool *d_graph_mask = nullptr;
    bool *d_updating_graph_mask = nullptr;
    bool *d_graph_visited = nullptr;
    int *d_cost = nullptr;
    int *d_stop = nullptr;

    cudaMalloc((void **)&d_graph_nodes, sizeof(Node) * no_of_nodes);
    cudaMalloc((void **)&d_graph_edges, sizeof(int) * edge_list_size);
    cudaMalloc((void **)&d_graph_mask, sizeof(bool) * no_of_nodes);
    cudaMalloc((void **)&d_updating_graph_mask, sizeof(bool) * no_of_nodes);
    cudaMalloc((void **)&d_graph_visited, sizeof(bool) * no_of_nodes);
    cudaMalloc((void **)&d_cost, sizeof(int) * no_of_nodes);
    cudaMalloc((void **)&d_stop, sizeof(int));

    cudaMemcpy(d_graph_nodes, h_graph_nodes, sizeof(Node) * no_of_nodes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_graph_edges, h_graph_edges, sizeof(int) * edge_list_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_graph_mask, h_graph_mask, sizeof(bool) * no_of_nodes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, sizeof(bool) * no_of_nodes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_graph_visited, h_graph_visited, sizeof(bool) * no_of_nodes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_cost, h_cost, sizeof(int) * no_of_nodes, cudaMemcpyHostToDevice);

    printf("Start traversing the tree\n");

    int k = 0;
    auto start_time = std::chrono::high_resolution_clock::now();

    bool stop;
    const int blockSize = 256;
    const int gridSize = (no_of_nodes + blockSize - 1) / blockSize;

    do
    {
        stop = false;
        int h_stop = 0;
        cudaMemcpy(d_stop, &h_stop, sizeof(int), cudaMemcpyHostToDevice);

        bfs_kernel_expand<<<gridSize, blockSize>>>(
            no_of_nodes,
            d_graph_nodes,
            d_graph_edges,
            d_graph_mask,
            d_updating_graph_mask,
            d_graph_visited,
            d_cost);

        bfs_kernel_update<<<gridSize, blockSize>>>(
            no_of_nodes,
            d_graph_mask,
            d_updating_graph_mask,
            d_graph_visited,
            d_stop);

        cudaMemcpy(&h_stop, d_stop, sizeof(int), cudaMemcpyDeviceToHost);
        stop = (h_stop != 0);
        k++;
    } while (stop);

    cudaMemcpy(h_cost, d_cost, sizeof(int) * no_of_nodes, cudaMemcpyDeviceToHost);

    auto end_time = std::chrono::high_resolution_clock::now();
    double elapsed = std::chrono::duration<double>(end_time - start_time).count();
    printf("Compute time: %lf\n", elapsed);

    FILE *fpo = fopen("result.txt", "w");
    for (int i = 0; i < no_of_nodes; i++)
        fprintf(fpo, "%d) cost:%d\n", i, h_cost[i]);
    fclose(fpo);
    printf("Result stored in result.txt\n");

    cudaFree(d_graph_nodes);
    cudaFree(d_graph_edges);
    cudaFree(d_graph_mask);
    cudaFree(d_updating_graph_mask);
    cudaFree(d_graph_visited);
    cudaFree(d_cost);
    cudaFree(d_stop);

    free(h_graph_nodes);
    free(h_graph_edges);
    free(h_graph_mask);
    free(h_updating_graph_mask);
    free(h_graph_visited);
    free(h_cost);
}

