					void *v)
{
  list_item_t *itr;
  list_item_t *i;

  i = (list_item_t *)malloc(sizeof (*i));
  list_item_init(i, v);

  if (l->head) {
    for (itr = l->head; itr && l->compare(list_item_get_datum(i),
					  list_item_get_datum(itr)) < 0;
	 itr = itr->next)
      ;
    if (itr) {
      i->next = itr;
      i->pred = itr->pred;
      itr->pred = i;
      i->pred->next = i;
    } else {
      l->tail->next = i;
      i->pred = l->tail;
      i->next = NULL;
      l->tail = i;
    }
  } else {
    l->head = l->tail = i;
    i->pred = i->next = NULL;
  }
  l->length++;
}

void 
list_remove_item(	list_t *l, 
					list_item_t *i)
{
  if (i == l->head) {
    l->head = l->head->next;
    if (l->head)
      l->head->pred = NULL;
    else
      l->tail = NULL;
  } else if (i == l->tail) {
    l->tail = l->tail->pred;
    l->tail->next = NULL;
  } else {
    i->pred->next = i->next;
    i->next->pred = i->pred;
  }
  l->length--;
  list_item_delete(i, l->datum_delete);
}

