__global__ void kernel_findK(record *records,
                             knode *knodes,
                             long knodes_elem,
                             int order,
                             long maxheight,
                             int count,
                             long *currKnode,
                             long *offset,
                             int *keys,
                             record *ans)
{
    int bid = blockIdx.x * blockDim.x + threadIdx.x;
    if (bid >= count) return;

    int threadsPerBlock = order < 1024 ? order : 1024;
    long curr = currKnode[bid];
    long off = offset[bid];
    int key = keys[bid];

    for (long i = 0; i < maxheight; i++) {
        for (int thid = 0; thid < threadsPerBlock; thid++) {
            if ((knodes[curr].keys[thid] <= key) &&
                (knodes[curr].keys[thid + 1] > key)) {
                if (knodes[off].indices[thid] < knodes_elem) {
                    off = knodes[off].indices[thid];
                }
            }
        }
        curr = off;
    }

    int out = ans[bid].value;
    for (int thid = 0; thid < threadsPerBlock; thid++) {
        if (knodes[curr].keys[thid] == key) {
            out = records[knodes[curr].indices[thid]].value;
        }
    }

    currKnode[bid] = curr;
    offset[bid] = off;
    ans[bid].value = out;
}

__global__ void kernel_findRangeK(knode *knodes,
                                  long knodes_elem,
                                  int order,
                                  long maxheight,
                                  int count,
                                  long *currKnode,
                                  long *offset,
                                  long *lastKnode,
                                  long *offset_2,
                                  int *start,
                                  int *end,
                                  int *recstart,
                                  int *reclength)
{
    int bid = blockIdx.x * blockDim.x + threadIdx.x;
    if (bid >= count) return;

    int threadsPerBlock = order < 1024 ? order : 1024;
    long curr = currKnode[bid];
    long off = offset[bid];
    long last = lastKnode[bid];
    long off2 = offset_2[bid];
    int skey = start[bid];
    int ekey = end[bid];

    for (long i = 0; i < maxheight; i++) {
        for (int thid = 0; thid < threadsPerBlock; thid++) {
            if ((knodes[curr].keys[thid] <= skey) &&
                (knodes[curr].keys[thid + 1] > skey)) {
                if (knodes[curr].indices[thid] < knodes_elem) {
                    off = knodes[curr].indices[thid];
                }
            }
            if ((knodes[last].keys[thid] <= ekey) &&
                (knodes[last].keys[thid + 1] > ekey)) {
                if (knodes[last].indices[thid] < knodes_elem) {
                    off2 = knodes[last].indices[thid];
                }
            }
        }
        curr = off;
        last = off2;
    }

    int rs = recstart[bid];
    int rl = reclength[bid];

    for (int thid = 0; thid < threadsPerBlock; thid++) {
        if (knodes[curr].keys[thid] == skey) {
            rs = knodes[curr].indices[thid];
        }
    }

    for (int thid = 0; thid < threadsPerBlock; thid++) {
        if (knodes[last].keys[thid] == ekey) {
            rl = knodes[last].indices[thid] - rs + 1;
        }
    }

    currKnode[bid] = curr;
    offset[bid] = off;
    lastKnode[bid] = last;
    offset_2[bid] = off2;
    recstart[bid] = rs;
    reclength[bid] = rl;
}

