	krecords = (record *)kmalloc(size * sizeof(record));
	knodes = (knode *)kmalloc(max_nodes * sizeof(knode));

	queue = NULL; enqueue(root);
	node *n; knode *k;
	int i; long nodeindex = 0, recordindex = 0, queueindex = 0;
	knodes[0].location = nodeindex++;

	while (NULL != queue) {
		n = dequeue(); k = &knodes[queueindex]; k->location = queueindex++; k->is_leaf = n->is_leaf; k->num_keys = n->num_keys + 2;
		k->keys[0] = INT_MIN; k->keys[k->num_keys - 1] = INT_MAX;
		for (i = k->num_keys; order > i; i++) k->keys[i] = INT_MAX;
		if (!k->is_leaf) {
			k->indices[0] = nodeindex++;
			for (i = 1; k->num_keys - 1 > i; i++) { k->keys[i] = n->keys[i - 1]; enqueue((node *)n->pointers[i - 1]); k->indices[i] = nodeindex++; }
			enqueue((node *)n->pointers[i - 1]);
		} else {
			k->indices[0] = 0;
			for (i = 1; i < k->num_keys - 1; i++) { k->keys[i] = n->keys[i - 1]; krecords[recordindex].value = ((record *)n->pointers[i - 1])->value; k->indices[i] = recordindex++; }
		}
		k->indices[k->num_keys - 1] = queueindex;

		if (verbose) {
			printf("Successfully created knode with index %d\n", k->location);
			printf("Is Leaf: %d, Num Keys: %d\n", k->is_leaf, k->num_keys);
			printf("Pointers: "); for (i = 0; k->num_keys > i; i++) printf("%d | ", k->indices[i]);
			printf("\nKeys: "); for (i = 0; k->num_keys > i; i++) printf("%d | ", k->keys[i]); printf("\n\n");
		}
	}
	long mem_used = size * sizeof(record) + (nodeindex) * sizeof(knode);
	if (verbose) {
		for (int j = 0; j < size; j++) printf("%d ", krecords[j].value);
		printf("\nNumber of records = %d, sizeof(record)=%d, total=%d\n", (int)size, (int)sizeof(record), (int)(size * sizeof(record)));
		printf("Number of knodes = %d, sizeof(knode)=%d, total=%d\n", (int)nodeindex, (int)sizeof(knode), (int)((nodeindex) * sizeof(knode)));
		printf("\nDone Transformation. Mem used: %d\n", (int)mem_used);
	}
