int main(int argc, char** argv) {
	int cur_arg, cores_arg = 1;
	char *input_file = NULL, *command_file = NULL, *output = (char *)"output.txt";
	FILE *pFile;

	for (cur_arg = 1; argc > cur_arg; cur_arg++) {
		if (strcmp(argv[cur_arg], "cores") == 0) {
			if (cur_arg + 1 < argc) {
				if (1 == isInteger(argv[cur_arg + 1])) { cores_arg = atoi(argv[cur_arg + 1]); if (0 > cores_arg) { printf("ERROR: Wrong value to cores parameter, cannot be <=0\n"); return -1; } cur_arg = cur_arg + 1; }
				else { printf("ERROR: Value to cores parameter in not a number\n"); return 0; }
			}
		} else if (strcmp(argv[cur_arg], "file") == 0) {
			if (argc > cur_arg + 1) { input_file = argv[cur_arg + 1]; cur_arg += 1; }
			else { printf("ERROR: Missing value to -file parameter\n"); return -1; }
		} else if (strcmp(argv[cur_arg], "command") == 0) {
			if (cur_arg + 1 < argc) { command_file = argv[cur_arg + 1]; cur_arg += 1; }
			else { printf("ERROR: Missing value to command parameter\n"); return -1; }
		}
	}

	if ((input_file == NULL) || (NULL == command_file)) printf("Usage: ./b+tree file input_file command command_list\n");
	printf("Input File: %s \n", input_file);
	printf("Command File: %s \n", command_file);

	FILE *commandFile = fopen(command_file, "rb");
	if (NULL == commandFile) { fputs("Command File error", stderr); exit(1); }
	fseek(commandFile, 0, SEEK_END);
	long lSize = ftell(commandFile);
	rewind(commandFile);

	char *commandBuffer = (char *)malloc(sizeof(char) * lSize + 1);
	if (NULL == commandBuffer) { fputs("Command Buffer memory error", stderr); exit(2); }
	size_t result = fread(commandBuffer, 1, lSize, commandFile);
	commandBuffer[lSize] = '\0';
	if (lSize != (long)result) { fputs("Command file reading error", stderr); exit(3); }
	fclose(commandFile);

	printf("Command Buffer: \n");
	printf("%s", commandBuffer);

	pFile = fopen(output, "w+");
	if (pFile == NULL) { printf("Fail to open %s !\n", output); }
	else { fprintf(pFile, "******starting******\n"); fclose(pFile); }

	FILE *file_pointer;
	node *root = NULL;
	record *r;
	int input;
	char instruction;
	order = DEFAULT_ORDER;
	verbose_output = false;

	if (NULL != input_file) {
		printf("Getting input from file %s...\n", input_file);
		file_pointer = fopen(input_file, "r");
		if (NULL == file_pointer) { perror("Failure to open input file."); exit(EXIT_FAILURE); }
		fscanf(file_pointer, "%d\n", &input);
		size = input;
		while (!feof(file_pointer)) { fscanf(file_pointer, "%d\n", &input); root = insert(root, input, input); }
		fclose(file_pointer);
	} else { printf("ERROR: Argument -file missing\n"); return 0; }

	printf("Transforming data to a GPU suitable structure...\n");
	long mem_used = transform_to_cuda(root, 0);
	maxheight = height(root);
	long rootLoc = (long)knodes - (long)mem;

	char *commandPointer = commandBuffer;
	printf("Waiting for command\n");
	printf("> ");

	while (sscanf(commandPointer, "%c", &instruction) != EOF) {
		commandPointer++;
		switch (instruction) {
			case 'i':
				scanf("%d", &input); while (getchar() != (int)'\n'); root = insert(root, input, input); print_tree(root); break;
			case 'f':
				break;
			case 'p':
				scanf("%d", &input); while (getchar() != (int)'\n'); r = find(root, input, instruction == 'p'); if (r == NULL) printf("Record not found under key %d.\n", input); else printf("Record found: %d\n", r->value); break;
			case 'd':
				scanf("%d", &input); while (getchar() != (int)'\n'); root = (node *)deleteVal(root, input); print_tree(root); break;
			case 'x':
				while (getchar() != (int)'\n'); root = destroy_tree(root); print_tree(root); break;
			case 'l':
				while (getchar() != (int)'\n'); print_leaves(root); break;
			case 't':
				while (getchar() != (int)'\n'); print_tree(root); break;
			case 'v':
				while (getchar() != (int)'\n'); verbose_output = !verbose_output; break;
			case 'q':
				while (getchar() != (int)'\n'); return EXIT_SUCCESS;
			case 'k': {
				int count; sscanf(commandPointer, "%d", &count);
				while (*commandPointer != '\n' && *commandPointer != '\0') commandPointer++;
				printf("\n ******command: k count=%d \n", count);
				if (65535 < count) { printf("ERROR: Number of requested querries should be 65,535 at most. (limited by # of CUDA blocks)\n"); exit(0); }

				record *records = (record *)mem;
				long records_elem = (long)rootLoc / sizeof(record);
				(void)records_elem;
				knode *knodes_local = (knode *)((long)mem + (long)rootLoc);
				long knodes_elem = ((long)(mem_used) - (long)rootLoc) / sizeof(knode);

				long *currKnode = (long *)malloc(count * sizeof(long)); memset(currKnode, 0, count * sizeof(long));
				long *offset = (long *)malloc(count * sizeof(long)); memset(offset, 0, count * sizeof(long));
				int *keys = (int *)malloc(count * sizeof(int));
				for (int i = 0; i < count; i++) keys[i] = (int)((rand() / (float)RAND_MAX) * size);

				record *ans = (record *)malloc(sizeof(record) * count);
				for (int i = 0; count > i; i++) ans[i].value = -1;

				kernel_cpu(cores_arg, records, knodes_local, knodes_elem, order, maxheight, count, currKnode, offset, keys, ans);

				pFile = fopen(output, "a+");
				if (NULL == pFile) printf("Fail to open %s !\n", output);
				else {
					fprintf(pFile, "\n ******command: k count=%d \n", count);
					for (int i = 0; i < count; i++) fprintf(pFile, "%d    %d\n", i, ans[i].value);
					fprintf(pFile, " \n");
					fclose(pFile);
				}
				free(currKnode); free(offset); free(keys); free(ans);
				break;
			}
			case 'r': {
				int start, end; scanf("%d", &start); scanf("%d", &end); if (end < start) { input = start; start = end; end = input; }
				printf("For range %d to %d, ", start, end); list_t *ansList = findRange(root, start, end); printf("%d records found\n", list_get_length(ansList)); free(ansList); break;
			}
			case 'j': {
				int count; sscanf(commandPointer, "%d", &count);
				while (*commandPointer != '\n' && *commandPointer != '\0') commandPointer++;
				int rSize = 0;
				if (*commandPointer == '\n') commandPointer++;
				sscanf(commandPointer, "%d", &rSize);
				while (*commandPointer != '\n' && *commandPointer != '\0') commandPointer++;

				printf("\n******command: j count=%d, rSize=%d \n", count, rSize);
				if (rSize > size || 0 > rSize) { printf("Search range size is larger than data set size %d.\n", (int)size); exit(0); }

				knode *knodes_local = (knode *)((long)mem + (long)rootLoc);
				long knodes_elem = ((long)(mem_used) - (long)rootLoc) / sizeof(knode);

				long *currKnode = (long *)malloc(count * sizeof(long)); memset(currKnode, 0, count * sizeof(long));
				long *offset = (long *)malloc(count * sizeof(long)); memset(offset, 0, count * sizeof(long));
				long *lastKnode = (long *)malloc(count * sizeof(long)); memset(lastKnode, 0, count * sizeof(long));
				long *offset_2 = (long *)malloc(count * sizeof(long)); memset(offset_2, 0, count * sizeof(long));

				int *start = (int *)malloc(count * sizeof(int));
				int *end = (int *)malloc(count * sizeof(int));
				for (int i = 0; i < count; i++) { start[i] = (int)((rand() / (float)RAND_MAX) * size); end[i] = start[i] + rSize; if (size <= end[i]) { start[i] = start[i] - (end[i] - size); end[i] = size - 1; } }

				int *recstart = (int *)malloc(count * sizeof(int));
				int *reclength = (int *)malloc(count * sizeof(int));
				for (int i = 0; count > i; i++) { recstart[i] = 0; reclength[i] = 0; }

				kernel_cpu_2(cores_arg, knodes_local, knodes_elem, order, maxheight, count, currKnode, offset, lastKnode, offset_2, start, end, recstart, reclength);

				pFile = fopen(output, "a+");
				if (pFile == NULL) printf("Fail to open %s !\n", output);
				else {
					fprintf(pFile, "\n******command: j count=%d, rSize=%d \n", count, rSize);
					for (int i = 0; count > i; i++) fprintf(pFile, "%d    %d    %d\n", i, recstart[i], reclength[i]);
					fprintf(pFile, " \n");
					fclose(pFile);
				}

				free(currKnode); free(offset); free(lastKnode); free(offset_2); free(start); free(end); free(recstart); free(reclength);
				break;
			}
			default:
				break;
		}
		printf("> ");
	}
	printf("\n");
	free(mem);
	free(commandBuffer);
	return EXIT_SUCCESS;
}

