void enqueue(node* new_node){
	node *c;
	if (NULL == queue) { queue = new_node; queue->next = NULL; }
	else {
		c = queue;
		while (NULL != c->next) c = c->next;
		c->next = new_node;
		new_node->next = NULL;
	}
}

node *dequeue(void){
	node *n = queue;
	queue = queue->next;
	n->next = NULL;
	return n;
}

void print_leaves(node* root){
	int i; node *c = root;
