	void **temp_pointers = (void **)malloc(order * sizeof(void *));
	if (NULL == temp_pointers) { perror("Temporary pointers array."); exit(EXIT_FAILURE); }

	int insertion_index = 0, split, new_key, i, j;
	while (key > leaf->keys[insertion_index] && order - 1 > insertion_index) insertion_index++;

	for (i = 0, j = 0; leaf->num_keys > i; i++, j++) {
		if (insertion_index == j) j++;
		temp_keys[j] = leaf->keys[i];
		temp_pointers[j] = leaf->pointers[i];
	}
	temp_keys[insertion_index] = key;
	temp_pointers[insertion_index] = pointer;

	leaf->num_keys = 0;
	split = cut(order - 1);

	for (i = 0; split > i; i++) {
		leaf->pointers[i] = temp_pointers[i];
		leaf->keys[i] = temp_keys[i];
		leaf->num_keys++;
	}
	for (i = split, j = 0; order > i; i++, j++) {
		new_leaf->pointers[j] = temp_pointers[i];
		new_leaf->keys[j] = temp_keys[i];
		new_leaf->num_keys++;
	}

	free(temp_pointers); free(temp_keys);

	new_leaf->pointers[order - 1] = leaf->pointers[order - 1];
	leaf->pointers[order - 1] = new_leaf;
	for (i = leaf->num_keys; order - 1 > i; i++) leaf->pointers[i] = NULL;
	for (i = new_leaf->num_keys; order - 1 > i; i++) new_leaf->pointers[i] = NULL;

	new_leaf->parent = leaf->parent;
	new_key = new_leaf->keys[0];

	return insert_into_parent(root, leaf, new_key, new_leaf);
}

