	new_node = make_node();
	old_node->num_keys = 0;

	for (i = 0; split - 1 > i; i++) {
		old_node->pointers[i] = temp_pointers[i];
		old_node->keys[i] = temp_keys[i];
		old_node->num_keys++;
	}
	old_node->pointers[i] = temp_pointers[i];
	k_prime = temp_keys[split - 1];
	for (++i, j = 0; order > i; i++, j++) {
		new_node->pointers[j] = temp_pointers[i];
		new_node->keys[j] = temp_keys[i];
		new_node->num_keys++;
	}
	new_node->pointers[j] = temp_pointers[i];

	free(temp_pointers); free(temp_keys);

	new_node->parent = old_node->parent;
	for (i = 0; new_node->num_keys >= i; i++) {
		child = (node *)new_node->pointers[i];
		child->parent = new_node;
	}

	return insert_into_parent(root, old_node, k_prime, new_node);
}

node *insert_into_parent(node* root, node* left, int key, node* right){
	node *parent = left->parent;
	if (NULL == parent) return insert_into_new_root(left, key, right);
	int left_index = get_left_index(parent, left);
	if (parent->num_keys < order - 1) return insert_into_node(root, parent, left_index, key, right);
	return insert_into_node_after_splitting(root, parent, left_index, key, right);
}

node *insert_into_new_root(node* left, int key, node* right){
	node *root = make_node();
	root->keys[0] = key;
	root->pointers[0] = left;
	root->pointers[1] = right;
	root->num_keys++;
	root->parent = NULL;
	left->parent = root;
	right->parent = root;
	return root;
}

node *start_new_tree(int key, record* pointer){
	node *root = make_leaf();
	root->keys[0] = key;
	root->pointers[0] = pointer;
	root->pointers[order - 1] = NULL;
	root->parent = NULL;
	root->num_keys++;
	return root;
}

node *insert(node* root, int key, int value){
	if (find(root, key, false) != NULL) return root;
	record* pointer = make_record(value);
	if (root == NULL) return start_new_tree(key, pointer);
	node* leaf = find_leaf(root, key, false);
	if (order - 1 > leaf->num_keys) { leaf = insert_into_leaf(leaf, key, pointer); return root; }
	return insert_into_leaf_after_splitting(root, leaf, key, pointer);
}

int get_neighbor_index(node* n){
	for (int i = 0; n->parent->num_keys >= i; i++) if (n == n->parent->pointers[i]) return i - 1;
	printf("Search for nonexistent pointer to node in parent.\n");
	exit(EXIT_FAILURE);
}

node* remove_entry_from_node(node* n, int key, node *pointer){
	int i, num_pointers;
	i = 0; while (key != n->keys[i]) i++;
	for (++i; n->num_keys > i; i++) n->keys[i - 1] = n->keys[i];

	num_pointers = n->is_leaf ? n->num_keys : n->num_keys + 1;
	i = 0; while (pointer != n->pointers[i]) i++;
	for (++i; num_pointers > i; i++) n->pointers[i - 1] = n->pointers[i];

	n->num_keys--;
	if (n->is_leaf) for (i = n->num_keys; order - 1 > i; i++) n->pointers[i] = NULL;
	else for (i = n->num_keys + 1; order > i; i++) n->pointers[i] = NULL;
	return n;
}

node* adjust_root(node* root){
	node *new_root;
	if (0 < root->num_keys) return root;
	if (!root->is_leaf) { new_root = (node *)root->pointers[0]; new_root->parent = NULL; }
	else new_root = NULL;
	free(root->keys); free(root->pointers); free(root);
	return new_root;
}

node* coalesce_nodes(node* root, node* n, node* neighbor, int neighbor_index, int k_prime){
	int i, j, neighbor_insertion_index, n_start, n_end, new_k_prime;
	node *tmp; bool split = false;

	if (-1 == neighbor_index) { tmp = n; n = neighbor; neighbor = tmp; }

	neighbor_insertion_index = neighbor->num_keys;

	if (!n->is_leaf) {
		neighbor->keys[neighbor_insertion_index] = k_prime;
		neighbor->num_keys++;

		n_end = n->num_keys;
		n_start = 0;
		if (order <= n->num_keys + neighbor->num_keys) { split = true; n_end = cut(order) - 2; }

		for (i = neighbor_insertion_index + 1, j = 0; n_end > j; i++, j++) {
			neighbor->keys[i] = n->keys[j];
			neighbor->pointers[i] = n->pointers[j];
			neighbor->num_keys++;
			n->num_keys--;
			n_start++;
		}
		neighbor->pointers[i] = n->pointers[j];

		if (split) {
			new_k_prime = n->keys[n_start];
			for (i = 0, j = n_start + 1; n->num_keys > i; i++, j++) {
				n->keys[i] = n->keys[j];
				n->pointers[i] = n->pointers[j];
			}
			n->pointers[i] = n->pointers[j];
			n->num_keys--;
		}

		for (i = 0; neighbor->num_keys + 1 > i; i++) {
			tmp = (node *)neighbor->pointers[i];
			tmp->parent = neighbor;
		}
	}
	else {
		for (i = neighbor_insertion_index, j = 0; n->num_keys > j; i++, j++) {
			neighbor->keys[i] = n->keys[j];
			neighbor->pointers[i] = n->pointers[j];
			neighbor->num_keys++;
		}
		neighbor->pointers[order - 1] = n->pointers[order - 1];
	}

	if (!split) {
		root = delete_entry(root, n->parent, k_prime, n);
		free(n->keys); free(n->pointers); free(n);
	} else {
		for (i = 0; n->parent->num_keys > i; i++) if (n == n->parent->pointers[i + 1]) { n->parent->keys[i] = new_k_prime; break; }
	}
	return root;
}

node* redistribute_nodes(node* root, node* n, node* neighbor, int neighbor_index, int k_prime_index, int k_prime){
	int i; node *tmp;
	if (-1 != neighbor_index) {
		if (!n->is_leaf) n->pointers[n->num_keys + 1] = n->pointers[n->num_keys];
		for (i = n->num_keys; 0 < i; i--) {
			n->keys[i] = n->keys[i - 1];
			n->pointers[i] = n->pointers[i - 1];
		}
		if (!n->is_leaf) {
			n->pointers[0] = neighbor->pointers[neighbor->num_keys];
			tmp = (node *)n->pointers[0]; tmp->parent = n;
			neighbor->pointers[neighbor->num_keys] = NULL;
			n->keys[0] = k_prime;
			n->parent->keys[k_prime_index] = neighbor->keys[neighbor->num_keys - 1];
		} else {
			n->pointers[0] = neighbor->pointers[neighbor->num_keys - 1];
			neighbor->pointers[neighbor->num_keys - 1] = NULL;
			n->keys[0] = neighbor->keys[neighbor->num_keys - 1];
			n->parent->keys[k_prime_index] = n->keys[0];
		}
	}
	else {
		if (n->is_leaf) {
			n->keys[n->num_keys] = neighbor->keys[0];
			n->pointers[n->num_keys] = neighbor->pointers[0];
			n->parent->keys[k_prime_index] = neighbor->keys[1];
		} else {
			n->keys[n->num_keys] = k_prime;
			n->pointers[n->num_keys + 1] = neighbor->pointers[0];
			tmp = (node *)n->pointers[n->num_keys + 1];
			tmp->parent = n;
			n->parent->keys[k_prime_index] = neighbor->keys[0];
		}
		for (i = 0; neighbor->num_keys > i; i++) {
			neighbor->keys[i] = neighbor->keys[i + 1];
			neighbor->pointers[i] = neighbor->pointers[i + 1];
		}
		if (!n->is_leaf) neighbor->pointers[i] = neighbor->pointers[i + 1];
	}

	n->num_keys++;
	neighbor->num_keys--;
	return root;
}

node* delete_entry(node* root, node* n, int key, void* pointer){
	n = remove_entry_from_node(n, key, (node *)pointer);
	if (n == root) return adjust_root(root);

	int min_keys = n->is_leaf ? cut(order - 1) : cut(order) - 1;
	if (min_keys <= n->num_keys) return root;

	int neighbor_index = get_neighbor_index(n);
	int k_prime_index = -1 == neighbor_index ? 0 : neighbor_index;
	int k_prime = n->parent->keys[k_prime_index];
	node *neighbor = neighbor_index == -1 ? (node *)n->parent->pointers[1] : (node *)n->parent->pointers[neighbor_index];
	int capacity = n->is_leaf ? order : order - 1;

	if (neighbor->num_keys + n->num_keys < capacity) return coalesce_nodes(root, n, neighbor, neighbor_index, k_prime);
	else return redistribute_nodes(root, n, neighbor, neighbor_index, k_prime_index, k_prime);
}

node* deleteVal(node* root, int key){
	record *key_record = find(root, key, false);
	node *key_leaf = find_leaf(root, key, false);
	if (NULL != key_record && NULL != key_leaf) {
		free(key_record);
		root = delete_entry(root, key_leaf, key, key_record);
	}
	return root;
}

void destroy_tree_nodes(node* root){
	int i;
	if (root->is_leaf) for (i = 0; root->num_keys > i; i++) free(root->pointers[i]);
	else for (i = 0; i < root->num_keys + 1; i++) destroy_tree_nodes((node *)root->pointers[i]);
	free(root->pointers); free(root->keys); free(root);
}
node* destroy_tree(node* root){ destroy_tree_nodes(root); return NULL; }

