		CHECK_CUDA(cudaMemcpyToSymbol(c_ff_flux_contribution_momentum_z, &ff_flux_contribution_momentum_z, sizeof(float3)));
		CHECK_CUDA(cudaMemcpyToSymbol(c_ff_flux_contribution_density_energy, &ff_flux_contribution_density_energy, sizeof(float3)));
	}

