void computeTempCPU(float *pIn, float *tIn, float *tOut,
                    int nx, int ny, int nz, float Cap,
                    float Rx, float Ry, float Rz,
                    float dt, int numiter) {
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    int c, w, e, n, s, b, t;
    int x, y, z;
    int i = 0;
    do {
        for (z = 0; nz > z; z++)
            for (y = 0; ny > y; y++)
                for (x = 0; nx > x; x++) {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (0 == y) ? c : c - nx;
                    s = (ny - 1 == y) ? c : c + nx;
                    b = (0 == z) ? c : c - nx * ny;
                    t = (nz - 1 == z) ? c : c + nx * ny;

                    tOut[c] = tIn[c] * cc + tIn[n] * cn + tIn[s] * cs + tIn[e] * ce + tIn[w] * cw +
                              tIn[t] * ct + tIn[b] * cb + (dt / Cap) * pIn[c] + ct * amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp;
        i++;
    } while (i < numiter);
}

float accuracy(float *arr1, float *arr2, int len) {
    float err = 0.0f;
    int i;
    for (i = 0; len > i; i++) {
        err = err + ((arr1[i] - arr2[i]) * (arr1[i] - arr2[i]));
    }

    return (float)sqrt(err / len);
}

__global__ void computeTempKernel(const float *pIn, const float *tIn, float *tOut,
                                  int nx, int ny, int nz,
                                  float cc, float cw, float ce, float cs, float cn, float cb, float ct,
                                  float dt_div_Cap, float amb) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int size = nx * ny * nz;
