    int z = idx / (nx * ny);
    int rem = idx - z * nx * ny;
    int y = rem / nx;
    int x = rem - y * nx;

    int c = idx;
    int w = (x == 0) ? c : c - 1;
    int e = (x == nx - 1) ? c : c + 1;
    int n = (y == 0) ? c : c - nx;
    int s = (y == ny - 1) ? c : c + nx;
    int b = (z == 0) ? c : c - nx * ny;
    int t = (z == nz - 1) ? c : c + nx * ny;

    tOut[c] = cc * tIn[c] + cw * tIn[w] + ce * tIn[e]
            + cs * tIn[s] + cn * tIn[n] + cb * tIn[b] + ct * tIn[t]
            + dt_div_Cap * pIn[c] + ct * amb;
