void computeTempOMP(float *pIn, float *tIn, float *tOut,
                    int nx, int ny, int nz, float Cap,
                    float Rx, float Ry, float Rz,
                    float dt, int numiter) {
    float ce, cw, cn, cs, ct, cb, cc;

    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    printf("%d threads running\n", 1);

    int size = nx * ny * nz;
    size_t bytes = (size_t)size * sizeof(float);

    float *dP = NULL, *dTempIn = NULL, *dTempOut = NULL;
    cudaCheck(cudaMalloc((void **)&dP, bytes), "cudaMalloc dP");
    cudaCheck(cudaMalloc((void **)&dTempIn, bytes), "cudaMalloc dTempIn");
    cudaCheck(cudaMalloc((void **)&dTempOut, bytes), "cudaMalloc dTempOut");

    cudaCheck(cudaMemcpy(dP, pIn, bytes, cudaMemcpyHostToDevice), "cudaMemcpy pIn H2D");
    cudaCheck(cudaMemcpy(dTempIn, tIn, bytes, cudaMemcpyHostToDevice), "cudaMemcpy tIn H2D");
    cudaCheck(cudaMemcpy(dTempOut, tOut, bytes, cudaMemcpyHostToDevice), "cudaMemcpy tOut H2D");

    float *tIn_t = dTempIn;
    float *tOut_t = dTempOut;

    int threads = 256;
    int blocks = (size + threads - 1) / threads;

    int count = 0;
    do {
        computeTempKernel<<<blocks, threads>>>(dP, tIn_t, tOut_t, nx, ny, nz,
                                               cc, cw, ce, cs, cn, cb, ct,
                                               dt / Cap, amb_temp);
        cudaCheck(cudaGetLastError(), "kernel launch");
        cudaCheck(cudaDeviceSynchronize(), "kernel sync");

        float *t = tIn_t;
        tIn_t = tOut_t;
        tOut_t = t;
        count++;
    } while (numiter > count);

    cudaCheck(cudaMemcpy(tIn, dTempIn, bytes, cudaMemcpyDeviceToHost), "cudaMemcpy dTempIn D2H");
    cudaCheck(cudaMemcpy(tOut, dTempOut, bytes, cudaMemcpyDeviceToHost), "cudaMemcpy dTempOut D2H");

    cudaFree(dP);
    cudaFree(dTempIn);
    cudaFree(dTempOut);
    return;
}

