__global__ void nw_top_left_kernel(int *input_itemsets, const int *referrence,
                                   int max_cols, int penalty, int blk) {
    int b_index_x = blockIdx.x * blockDim.x + threadIdx.x;
    if (b_index_x >= blk) return;

    int b_index_y = blk - 1 - b_index_x;
    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                          b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                              b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                    reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                          b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void nw_bottom_right_kernel(int *input_itemsets, const int *referrence,
                                       int max_cols, int penalty, int blk, int num_blocks) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int start_x = blk - 1;
    int count = num_blocks - start_x;
    if (tid >= count) return;

    int b_index_x = start_x + tid;
    int b_index_y = num_blocks + blk - 2 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                          b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                              b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                    reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                          b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

