void usage(int argc, char **argv) {
    fprintf(stderr, "Usage: %s <max_rows/max_cols> <penalty> <num_threads>\n", argv[0]);
    fprintf(stderr, "\t<dimension>      - x and y dimensions\n");
    fprintf(stderr, "\t<penalty>        - penalty(positive integer)\n");
    fprintf(stderr, "\t<num_threads>    - no. of threads\n");
    exit(1);
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
                  int max_rows, int max_cols, int penalty) {
    (void)output_itemsets;
    int transfer_size = max_rows * max_cols;

    int *d_input_itemsets = NULL;
    int *d_referrence = NULL;

    cudaCheck(cudaMalloc((void **)&d_input_itemsets, transfer_size * sizeof(int)), "cudaMalloc d_input_itemsets");
    cudaCheck(cudaMalloc((void **)&d_referrence, transfer_size * sizeof(int)), "cudaMalloc d_referrence");

    cudaCheck(cudaMemcpy(d_input_itemsets, input_itemsets, transfer_size * sizeof(int), cudaMemcpyHostToDevice),
              "cudaMemcpy H2D input_itemsets");
    cudaCheck(cudaMemcpy(d_referrence, referrence, transfer_size * sizeof(int), cudaMemcpyHostToDevice),
              "cudaMemcpy H2D referrence");

    int num_blocks = (max_cols - 1) / BLOCK_SIZE;
    const int threads = 128;

    for (int blk = 1; blk <= num_blocks; blk++) {
        int count = blk;
        int grid = (count + threads - 1) / threads;
        nw_top_left_kernel<<<grid, threads>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk);
        cudaCheck(cudaGetLastError(), "nw_top_left_kernel launch");
    }

    cudaCheck(cudaDeviceSynchronize(), "sync after top-left");
    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= num_blocks; blk++) {
        int count = num_blocks - (blk - 1);
        int grid = (count + threads - 1) / threads;
        nw_bottom_right_kernel<<<grid, threads>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk, num_blocks);
        cudaCheck(cudaGetLastError(), "nw_bottom_right_kernel launch");
    }

    cudaCheck(cudaDeviceSynchronize(), "sync after bottom-right");

    cudaCheck(cudaMemcpy(input_itemsets, d_input_itemsets, transfer_size * sizeof(int), cudaMemcpyDeviceToHost),
              "cudaMemcpy D2H input_itemsets");

    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

void runTest(int argc, char **argv) {
    int max_rows, max_cols, penalty;
    int *input_itemsets, *output_itemsets, *referrence;
    int omp_num_threads;

    if (argc == 4) {
        max_rows = atoi(argv[1]);
        max_cols = atoi(argv[1]);
        penalty = atoi(argv[2]);
        omp_num_threads = atoi(argv[3]);
    } else {
        usage(argc, argv);
    }

    max_rows = max_rows + 1;
    max_cols = max_cols + 1;
    referrence = (int *)malloc(max_rows * max_cols * sizeof(int));
    input_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));
    output_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));

    if (!input_itemsets)
        fprintf(stderr, "error: can not allocate memory");

    srand(7);

    for (int i = 0; i < max_cols; i++) {
        for (int j = 0; j < max_rows; j++) {
            input_itemsets[i * max_cols + j] = 0;
        }
    }

    printf("Start Needleman-Wunsch\n");

    for (int i = 1; i < max_rows; i++) {
        input_itemsets[i * max_cols] = rand() % 10 + 1;
    }
    for (int j = 1; j < max_cols; j++) {
        input_itemsets[j] = rand() % 10 + 1;
    }

    for (int i = 1; i < max_cols; i++) {
        for (int j = 1; j < max_rows; j++) {
            referrence[i * max_cols + j] = blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
        }
    }

    for (int i = 1; i < max_rows; i++)
        input_itemsets[i * max_cols] = -i * penalty;
    for (int j = 1; j < max_cols; j++)
        input_itemsets[j] = -j * penalty;

    printf("Num of threads: %d\n", omp_num_threads);
    printf("Processing top-left matrix\n");

    long long start_time = get_time();

    nw_optimized(input_itemsets, output_itemsets, referrence, max_rows, max_cols, penalty);

    long long end_time = get_time();

    printf("Total time: %.3f seconds\n", ((float)(end_time - start_time)) / (1000 * 1000));

#define TRACEBACK
#ifdef TRACEBACK
    FILE *fpo = fopen("result.txt", "w");
    fprintf(fpo, "print traceback value GPU:\n");

    for (int i = max_rows - 2, j = max_rows - 2; i >= 0, j >= 0;) {
        int nw, n, w, traceback;
        if (i == max_rows - 2 && j == max_rows - 2)
            fprintf(fpo, "%d ", input_itemsets[i * max_cols + j]);
        if (i == 0 && j == 0)
            break;
        if (i > 0 && j > 0) {
            nw = input_itemsets[(i - 1) * max_cols + j - 1];
            w = input_itemsets[i * max_cols + j - 1];
            n = input_itemsets[(i - 1) * max_cols + j];
        } else if (i == 0) {
            nw = n = LIMIT;
            w = input_itemsets[i * max_cols + j - 1];
        } else if (j == 0) {
            nw = w = LIMIT;
            n = input_itemsets[(i - 1) * max_cols + j];
        } else {
        }

        int new_nw, new_w, new_n;
        new_nw = nw + referrence[i * max_cols + j];
        new_w = w - penalty;
        new_n = n - penalty;

        traceback = maximum(new_nw, new_w, new_n);
        if (traceback == new_nw)
            traceback = nw;
        if (traceback == new_w)
            traceback = w;
        if (traceback == new_n)
            traceback = n;

        fprintf(fpo, "%d ", traceback);

        if (traceback == nw) {
            i--;
            j--;
            continue;
        } else if (traceback == w) {
            j--;
            continue;
        } else if (traceback == n) {
            i--;
            continue;
        } else
            ;
    }

    fclose(fpo);
#endif

    free(referrence);
    free(input_itemsets);
    free(output_itemsets);
}

