void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
                  int max_rows, int max_cols, int penalty) {
    (void)output_itemsets;
    (void)max_rows;

    int transfer_size = max_rows * max_cols;
    int *d_input = NULL;
    int *d_ref = NULL;

    cudaCheck(cudaMalloc((void**)&d_input, transfer_size * sizeof(int)), "cudaMalloc d_input");
    cudaCheck(cudaMalloc((void**)&d_ref, transfer_size * sizeof(int)), "cudaMalloc d_ref");

    cudaCheck(cudaMemcpy(d_input, input_itemsets, transfer_size * sizeof(int), cudaMemcpyHostToDevice),
              "cudaMemcpy input H2D");
    cudaCheck(cudaMemcpy(d_ref, referrence, transfer_size * sizeof(int), cudaMemcpyHostToDevice),
              "cudaMemcpy ref H2D");

    int blocks = (max_cols - 1) / BLOCK_SIZE;

    for (int blk = 1; blk <= blocks; blk++) {
        nw_top_left_kernel<<<blk, 1>>>(d_input, d_ref, max_cols, penalty, blk);
        cudaCheck(cudaGetLastError(), "nw_top_left_kernel launch");
        cudaCheck(cudaDeviceSynchronize(), "nw_top_left_kernel sync");
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= blocks; blk++) {
        int grid = blocks - blk + 1;
        nw_bottom_right_kernel<<<grid, 1>>>(d_input, d_ref, max_cols, penalty, blk, blocks);
        cudaCheck(cudaGetLastError(), "nw_bottom_right_kernel launch");
        cudaCheck(cudaDeviceSynchronize(), "nw_bottom_right_kernel sync");
    }

    cudaCheck(cudaMemcpy(input_itemsets, d_input, transfer_size * sizeof(int), cudaMemcpyDeviceToHost),
              "cudaMemcpy input D2H");

    cudaFree(d_input);
    cudaFree(d_ref);
}

