        }
        long long u_time = get_time();
        printf("TIME TO CALC U TOOK: %f\n", elapsed_time(cum_sum, u_time));

        check_error(cudaMemcpy(arrayX_GPU, arrayX, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_error(cudaMemcpy(arrayY_GPU, arrayY, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_error(cudaMemcpy(CDF_GPU, CDF, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_error(cudaMemcpy(u_GPU, u, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));

        int num_blocks = (Nparticles + threads_per_block - 1) / threads_per_block;
        resample_kernel<<<num_blocks, threads_per_block>>>(arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, Nparticles);
        check_error(cudaGetLastError());
        check_error(cudaDeviceSynchronize());

        check_error(cudaMemcpy(xj, xj_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
        check_error(cudaMemcpy(yj, yj_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));

        long long xyj_time = get_time();
        printf("TIME TO CALC NEW ARRAY X AND Y TOOK: %f\n", elapsed_time(u_time, xyj_time));

        for (x = 0; x < Nparticles; x++) {
            arrayX[x] = xj[x];
            arrayY[x] = yj[x];
            weights[x] = 1 / ((double)(Nparticles));
        }
        long long reset = get_time();
        printf("TIME TO RESET WEIGHTS TOOK: %f\n", elapsed_time(xyj_time, reset));
    }

    check_error(cudaFree(yj_GPU));
    check_error(cudaFree(xj_GPU));
    check_error(cudaFree(u_GPU));
    check_error(cudaFree(CDF_GPU));
    check_error(cudaFree(arrayY_GPU));
    check_error(cudaFree(arrayX_GPU));

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(xj);
    free(yj);
    free(arrayX);
    free(arrayY);
    free(CDF);
    free(u);
    free(ind);
}

