__global__ void pathfinder_step_kernel(const int* wall_data, const int* src, int* dst, int cols, int row_idx)
{
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n < cols) {
        int minv = src[n];
        if (n > 0) minv = (minv <= src[n-1]) ? minv : src[n-1];
        if (n < cols-1) minv = (minv <= src[n+1]) ? minv : src[n+1];
        dst[n] = wall_data[row_idx * cols + n] + minv;
    }
}

