__global__ void path_kernel(const int* wall_flat, const int* src, int* dst, int row, int cols)
{
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n < cols) {
        int minv = src[n];
        if (n > 0) minv = (minv <= src[n - 1]) ? minv : src[n - 1];
        if (n < cols - 1) minv = (minv <= src[n + 1]) ? minv : src[n + 1];
        dst[n] = wall_flat[row * cols + n] + minv;
    }
}

